// Normalize both trigger paths into a consistent deal list
// Webhook: single deal from body
// Nightly: all active deals from Postgres
const items = $input.all();

// Webhook path — body has deal_id
if (items[0]?.json?.body?.deal_id) {
  const body = items[0].json.body;
  return [{
    json: {
      deal_id: body.deal_id,
      trigger_message_id: body.trigger_message_id || null,
      trigger_type: body.trigger_type || 'webhook'
    }
  }];
}

// Nightly path — items are rows from Postgres: Get All Active Deals
return items.map(item => ({
  json: {
    deal_id: item.json.deal_id,
    company_name: item.json.company_name,
    deal_stage: item.json.deal_stage,
    salesforce_stage: item.json.salesforce_stage,
    close_date: item.json.close_date,
    forecast_category: item.json.forecast_category,
    trigger_message_id: null,
    trigger_type: 'nightly'
  }
}));

// Merge deal context from Postgres with trigger metadata
// Guard: 30-minute cooldown for webhook triggers to prevent duplicate scoring
const triggerData = $('Code: Normalize Trigger').first().json;
const dealRow = $input.first().json;

if (!dealRow.deal_id) {
  return []; // deal not found — skip
}

const lastWasCalendarOnly = dealRow.last_trigger_type === 'calendar_only';
if (!lastWasCalendarOnly && dealRow.last_scored_at && triggerData.trigger_type === 'new_ingestion') {
  const minutesSince = (Date.now() - new Date(dealRow.last_scored_at).getTime()) / 60000;
  if (minutesSince < 30) {
    return []; // cooldown — skip
  }
}

return [{
  json: {
    deal_id: dealRow.deal_id,
    company_name: dealRow.company_name,
    deal_stage: dealRow.deal_stage || 'discover',
    salesforce_stage: dealRow.salesforce_stage || '',
    close_date: dealRow.close_date || null,
    forecast_category: dealRow.forecast_category || 'pipeline',
    last_scored_at: dealRow.last_scored_at || null,
    last_total: dealRow.last_total !== null && dealRow.last_total !== undefined ? dealRow.last_total : null,
    trigger_message_id: triggerData.trigger_message_id,
    trigger_type: triggerData.trigger_type
  }
}];

// Generate 15 targeted RAG queries — one per CPS dimension + supporting context areas.
// Each uses Clearwater-specific language (DAP, PES, ES, Champion).
const deal = $input.first().json;
const co = deal.company_name;

const queries = [
  { dimension: 'pain',         query: `What specific pain, urgent business problems, or compliance/cybersecurity challenges has ${co} articulated? What is driving urgency? What are the consequences of not acting? Has the Executive Sponsor agreed the pain is large enough to change?` },
  { dimension: 'power',        query: `Who has budget authority and final decision-making power at ${co}? Has Austin met with the Executive Sponsor (ES) or Potential Executive Sponsor (PES)? Who is the Champion? Has an ES agreed to a Dual Action Plan (DAP)?` },
  { dimension: 'vision',       query: `What future state vision of improved security and compliance has been co-created with ${co}? Has the ES agreed to a vision of improved future state? Is the ES painting this vision to others inside the organization?` },
  { dimension: 'value',        query: `What financial terms, ROI, cost of the problem, or investment levels have been discussed with ${co}? Has finance or the Decision Maker agreed to financial terms? Has the ES shared ROI projections with the DM?` },
  { dimension: 'change',       query: `What commitment to change has ${co} expressed? Has the Executive Sponsor acknowledged they must change? Has the ES convinced the ultimate Decision Maker (DM) that they must change? What board or leadership pressure exists? Are there any hard deadlines, contract renewals, vendor renewal conversations, MSP renewal timing, or external forcing functions that create urgency to make a decision by a specific date?` },
  { dimension: 'control',      query: `What is the buying process at ${co}? Is there a Dual Action Plan (DAP) with agreed milestones and dates? Has the ES agreed to the DAP? What is the procurement, legal, or approval process?` },
  { dimension: 'dap',          query: `What specific milestones, dates, and owners are in the action plan or DAP with ${co}? What steps have been completed and what remain open? Are there any gaps larger than 14 days between milestones? What is the next committed milestone date?` },
  { dimension: 'stakeholders', query: `Who are all key stakeholders at ${co}? What are their titles, roles, and level of engagement? Who is the Champion, Potential Champion, PES, ES, and final Decision Maker? What are their individual goals and success criteria?` },
  { dimension: 'current_state', query: `What is ${co}'s current cybersecurity and compliance posture? What security program, processes, tools, and gaps exist today? What assessments, audits, or incidents have been disclosed?` },
  { dimension: 'future_state', query: `What future state does ${co} want to achieve? What are their compliance goals, desired capabilities, and success criteria? What organizational, process, or technology improvements are they seeking?` },
  { dimension: 'risks',        query: `What are the key risks, objections, competitive threats, or obstacles in the ${co} deal? What could prevent or delay closing? Are there incumbent vendors, internal politics, or budget risks?` },
  { dimension: 'next_steps',   query: `What are the specific next steps, action items, and follow-ups agreed with ${co}? What is Austin committed to delivering and by when? What has the prospect committed to? When is the next scheduled meeting?` },
  { dimension: 'services',     query: `What Clearwater services, solutions, or engagement scope has been proposed or discussed with ${co}? What cybersecurity, risk, or compliance services are they interested in? What is the potential engagement size?` },
  { dimension: 'call_summary', query: `What happened in the most recent call or meeting with ${co}? What were the key discussion points, decisions made, and outcomes?` },
  { dimension: 'pe_sponsor',   query: `Who is the executive sponsor or PE/investor sponsor at ${co}? What is their level of support and commitment? Is there board-level or PE investor pressure driving this deal? Has Austin gained C-suite access?` }
];

return queries.map(q => ({
  json: { ...deal, rag_query: q.query, rag_dimension: q.dimension }
}));

// Collect all 15 RAG query results and assemble into a structured context block.
// HTTP Request nodes break pairedItem chains — match by index like CW-01.
const allSearchResults = $input.all();
const allQueryItems = $('Code: Build RAG Queries').all();
const dealData = $('Code: Merge Deal Context').first().json;

const dimensionChunks = {};

allSearchResults.forEach((item, i) => {
  const queryItem = allQueryItems[i] || allQueryItems[0];
  const dimension = queryItem.json.rag_dimension;
  const results = item.json.result || [];

  const chunks = results
    .filter(r => (r.score || 0) > 0.25)
    .map(r => {
      const p = r.payload || {};
      const date = p.date_created ? new Date(p.date_created).toISOString().split('T')[0] : 'unknown date';
      return `[${p.doc_type || 'document'}, ${date}]\n${p.page_content || ''}`;
    })
    .join('\n---\n');

  if (!dimensionChunks[dimension]) dimensionChunks[dimension] = [];
  if (chunks) dimensionChunks[dimension].push(chunks);
});

const contextBlock = Object.entries(dimensionChunks)
  .map(([dim, chunks]) => `=== ${dim.toUpperCase()} EVIDENCE ===\n${chunks.join('\n---\n') || '[No relevant content found]'}`)
  .join('\n\n');

return [{
  json: {
    ...dealData,
    rag_context: contextBlock || 'No deal content has been ingested yet for this deal.',
    context_dimensions: Object.keys(dimensionChunks)
  }
}];

// Build a parameterized INSERT SQL safely — avoids all quoting issues.
const d = $input.first().json;

// Helper: SQL-safe string literal (single-quoted, escaped apostrophes)
function sq(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

// Helper: SQL-safe date
function sd(val) {
  if (!val) return 'NULL';
  const s = String(val);
  if (!/^\d{4}-\d{2}-\d{2}/.test(s)) return 'NULL';
  return "'" + s.substring(0, 10) + "'::date";
}

// Helper: SQL-safe integer
function si(val) {
  const n = parseInt(val, 10);
  return isNaN(n) ? 'NULL' : String(n);
}

// Helper: SQL-safe boolean
function sb(val) {
  return val ? 'true' : 'false';
}

// Helper: SQL-safe text array
function sa(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return 'NULL::text[]';
  const escaped = arr.map(v => "'" + String(v).replace(/'/g, "''") + "'").join(',');
  return `ARRAY[${escaped}]::text[]`;
}

// Helper: SQL-safe JSONB
function sj(val) {
  if (!val || (Array.isArray(val) && val.length === 0)) return 'NULL';
  const s = JSON.stringify(val);
  return "'" + s.replace(/'/g, "''") + "'::jsonb";
}

