  return [{ json: { stakeholders_upserted: 0, scoring_run_id: scoringRunId } }];
}

const dealId = parseScoresData.deal_id;
const stakeholders = parseScoresData.stakeholders || [];
const scoredAt = new Date().toISOString();

if (stakeholders.length === 0) {
  return [{ json: { stakeholders_upserted: 0, scoring_run_id: scoringRunId } }];
}

function sq(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function sb(v) { return v ? 'TRUE' : 'FALSE'; }

const rows = stakeholders.map(s => {
  const name = s.name || '';
  if (!name) return null;
  return '(' + sq(dealId) + ', ' + (scoringRunId !== null ? scoringRunId : 'NULL') + ", '" + scoredAt + "', " +
    sq(name) + ', ' + sq(s.title) + ', ' + sq(s.email) + ', ' + sq(s.company) + ', ' +
    sq(s.cps_role || 'OTHER') + ', ' + sq(s.role_evidence) + ', ' +
    sb(s.directly_engaged) + ', ' + sq(s.success_criteria) + ')';
}).filter(r => r !== null);

if (rows.length === 0) {
  return [{ json: { stakeholders_upserted: 0, scoring_run_id: scoringRunId } }];
}

const sql = 'INSERT INTO deal_stakeholders\n' +
